+
+    #[test]
+    fn test_full_roundtrip_hot() {
+        let mut comp = TemporalTensorCompressor::new(default_policy(), 128, 0);
+        comp.set_access(100, 0);
+        let frame: Vec<f32> = (0..128).map(|i| (i as f32 - 64.0) * 0.01).collect();
+        let mut seg = Vec::new();
