+        .map(|_| (0..tensor_len as usize).map(|_| rng.next_f32() * 2.0 - 1.0).collect())
+        .collect();
+
+    let mut seg = Vec::new();
+    for (i, frame) in frames.iter().enumerate() {
+        comp.push_frame(frame, (i + 1) as u32, &mut seg);
+    }
