+    // Rank-1 matrix: data[i][j] = (i+1)*(j+1) / (m*n).
+    let data: Vec<f32> = (0..m * n)
+        .map(|idx| {
+            let (i, j) = (idx / n, idx % n);
+            (i as f32 + 1.0) * (j as f32 + 1.0) / (m * n) as f32
+        })
+        .collect();
