+// ============================================================================
+// Metadata Value
+// ============================================================================
+
+/// Metadata value types supported for GGUF export.
+#[derive(Debug, Clone)]
+pub enum MetadataValue {
+    /// Unsigned 32-bit integer
+    U32(u32),
+    /// Signed 32-bit integer
+    I32(i32),
+    /// UTF-8 string
+    String(String),
+}
