+        for &(input, expected) in cases {
+            let bytes = f32_to_f16_bytes(input);
+            let bits = u16::from_le_bytes(bytes);
+            let back = f16_to_f32(bits);
+            assert!(
+                (back - expected).abs() < 1e-3,
+                "f16 roundtrip failed for {}: got {}",
